import "math"

func solve(nums []int64) int64 {
	n := len(nums)
	if n < 3 {
		return 0
	}

	// L is the range of potential peak indices: 1 to N-2
	L := n - 2
	// K is the maximum number of non-adjacent peaks possible
	K := (L + 1) / 2

	// Step 1: Calculate cost C[i] for making index i a peak (i = 1 to L)
	// C is 1-indexed for convenience matching DP
	C := make([]int64, L+1)
	for i := 1; i <= L; i++ {
		leftNeighbor := nums[i-1]
		rightNeighbor := nums[i+1]

		requiredHeight := int64(math.Max(float64(leftNeighbor), float64(rightNeighbor))) + 1

		cost := int64(0)
		if requiredHeight > nums[i] {
			cost = requiredHeight - nums[i]
		}
		C[i] = cost
	}

	// Step 2: Dynamic Programming
	// DP[i][k]: Minimum cost to achieve k peaks using indices from {1, 2, ..., i}
	// Size: (L+1) x (K+1)

	infinity := int64(math.MaxInt64)

	dp := make([][]int64, L+1)
	for i := range dp {
		dp[i] = make([]int64, K+1)
		for k := range dp[i] {
			dp[i][k] = infinity
		}
	}

	// Base case: 0 peaks always costs 0
	for i := 0; i <= L; i++ {
		dp[i][0] = 0
	}

	// DP transition
	for i := 1; i <= L; i++ {
		for k := 1; k <= K; k++ {
			// Case 1: Do not select index i
			cost1 := dp[i-1][k]

			// Case 2: Select index i
			cost2 := infinity

			// If we select i, we must have selected k-1 peaks up to i-2
			if i >= 2 {
				if dp[i-2][k-1] != infinity {
					cost2 = dp[i-2][k-1] + C[i]
				}
			} else if i == 1 && k == 1 {
				// Base case for the first element
				cost2 = C[1]
			}

			// Choose the minimum
			dp[i][k] = min(cost1, cost2)
		}
	}

	return dp[L][K]
}

