// assuming non-adjacent peaks are chosen.
func calculateCost(nums []int64, start int) int64 {
	n := len(nums)
	if n < 3 {
		return 0
	}

	var totalCost int64 = 0
	// Iterate through potential peak indices i = start, start+2, start+4, ...
	for i := start; i <= n-2; i += 2 {
		// A peak at i requires nums[i] > nums[i-1] and nums[i] > nums[i+1]

		// Required value must be strictly greater than both neighbors
		L := nums[i-1]
		R := nums[i+1]

		requiredValue := max(L, R) + 1

		// Calculate cost: max(0, requiredValue - currentValue)
		costI := int64(0)
		if requiredValue > nums[i] {
			costI = requiredValue - nums[i]
		}
		totalCost += costI
	}
	return totalCost
}

func solve(nums []int64) int64 {
	n := len(nums)
	if n < 3 {
		return 0
	}

	// Candidate A: Peaks at 1, 3, 5, ...
	costA := calculateCost(nums, 1)

	// Candidate B: Peaks at 2, 4, 6, ...
	// This is only possible if N >= 4 (i.e., index 2 exists and is < N-1)
	var costB int64 = -1 // Use -1 to signify it might not be possible or we haven't calculated it yet

	if n >= 4 {
		costB = calculateCost(nums, 2)
	}

	// Determine the number of peaks achievable for A and B to maximize count first.

	// M_A: Number of peaks for A. Indices 1, 3, ..., up to N-2.
	// Number of terms in 1, 3, ..., 2k+1 where 2k+1 <= N-2.
	mA := (n - 2 + 1) / 2 

	// M_B: Number of peaks for B. Indices 2, 4, ..., up to N-2.
	// Number of terms in 2, 4, ..., 2k where 2k <= N-2.
	mB := 0
	if n >= 4 {
		mB = (n - 2) / 2
	}

	if mA > mB {
		return costA
	} else if mB > mA {
		return costB
	} else {
		// mA == mB (including the case where both are 0, though N>=3 guarantees mA>=1)
		return min(costA, costB)
	}
}
